import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { toast } from "react-toastify";
import {
  buscarTipo,
  criarTipo,
  atualizarTipo,
} from "../../services/tipoEntregaService";

export default function TipoEntregaForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEditing = Boolean(id);

  const [form, setForm] = useState({ descricao: "", prazoEmDias: "" });
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (isEditing) {
      setLoading(true);
      buscarTipo(id)
        .then((res) => setForm(res.data))
        .catch(() => toast.error("Erro ao carregar tipo de entrega."))
        .finally(() => setLoading(false));
    }
  }, [id, isEditing]);

  function handleChange(e) {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.descricao.trim()) {
      toast.warning("Informe a descrição do tipo de entrega.");
      return;
    }
    if (!form.prazoEmDias || Number(form.prazoEmDias) < 1) {
      toast.warning("Informe um prazo válido em dias.");
      return;
    }

    try {
      setSaving(true);
      const payload = {
        descricao: form.descricao.trim(),
        prazoEmDias: Number(form.prazoEmDias),
      };

      if (isEditing) {
        await atualizarTipo(id, payload);
        toast.success("Tipo de entrega atualizado com sucesso!");
      } else {
        await criarTipo(payload);
        toast.success("Tipo de entrega cadastrado com sucesso!");
      }
      navigate("/tipos-entrega");
    } catch {
      toast.error("Erro ao salvar tipo de entrega.");
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div style={{ padding: 32 }}>
        <div className="shimmer-row" style={{ maxWidth: 400 }} />
        <div className="shimmer-row" style={{ maxWidth: 400, marginTop: 10 }} />
      </div>
    );
  }

  return (
    <div className="form-card">
      <div className="form-card-header">
        <i className="bi bi-tags" />
        {isEditing ? "Editar Tipo de Entrega" : "Novo Tipo de Entrega"}
      </div>

      <form className="form-card-body" onSubmit={handleSubmit}>
        <div style={{ marginBottom: 18 }}>
          <label className="form-label-custom">
            Descrição <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <input
            className="form-control-custom"
            name="descricao"
            value={form.descricao}
            onChange={handleChange}
            placeholder="Ex: Sedex, PAC, Motoboy..."
            maxLength={100}
          />
        </div>

        <div style={{ marginBottom: 18 }}>
          <label className="form-label-custom">
            Prazo em Dias <span style={{ color: "var(--danger)" }}>*</span>
          </label>
          <input
            className="form-control-custom"
            name="prazoEmDias"
            type="number"
            min="1"
            value={form.prazoEmDias}
            onChange={handleChange}
            placeholder="Ex: 7"
          />
          <div className="form-hint">
            A data prevista de entrega será calculada automaticamente com base
            neste prazo.
          </div>
        </div>

        <div className="form-actions">
          <button
            className="btn-primary-custom"
            type="submit"
            disabled={saving}
          >
            {saving ? (
              <>
                <span
                  className="spinner-border spinner-border-sm"
                  style={{ marginRight: 6 }}
                />
                Salvando...
              </>
            ) : (
              <>
                <i className="bi bi-check-lg" />
                {isEditing ? "Salvar alterações" : "Cadastrar"}
              </>
            )}
          </button>
          <button
            className="btn-secondary-custom"
            type="button"
            onClick={() => navigate("/tipos-entrega")}
          >
            Cancelar
          </button>
        </div>
      </form>
    </div>
  );
}
